import { writeFileSync } from "node:fs";

import type { BaselineMetrics, ObservedMetrics, ReferenceMetrics } from "@dec-bench/scenarios";

import { createAssertionContext } from "./context.js";
import { runGateEvaluation } from "./runner.js";

function parseNumber(input: string | undefined, fallback: number): number {
  if (!input) {
    return fallback;
  }
  const parsed = Number(input);
  return Number.isFinite(parsed) ? parsed : fallback;
}

function parseJsonEnv<T>(envKey: string): T | undefined {
  const raw = process.env[envKey];
  if (!raw) return undefined;
  try {
    return JSON.parse(raw) as T;
  } catch {
    return undefined;
  }
}

async function main(): Promise<void> {
  const assertionsDir = process.argv[2];
  if (!assertionsDir) {
    throw new Error("Usage: node cli.js <assertions-dir>");
  }

  const processExitCode = parseNumber(process.env.AGENT_EXIT_CODE, 0);
  const wallClockSeconds = parseNumber(process.env.EVAL_WALL_CLOCK_SECONDS, 0);
  const agentSteps = parseNumber(process.env.EVAL_AGENT_STEPS, 0);
  const tokensUsed = parseNumber(process.env.EVAL_TOKENS_USED, 0);
  const llmApiCostUsd = parseNumber(process.env.EVAL_LLM_API_COST_USD, 0);
  const assertionLogPath = process.env.ASSERTION_LOG_PATH ?? "/output/assertion-log.json";
  const runMetadata = parseJsonEnv<{
    persona: string;
    planMode: string;
    promptPath: string;
    promptSha256: string;
    promptContent: string;
    promptPreview?: string;
  }>("EVAL_RUN_METADATA_JSON");

  const baselineMetrics = parseJsonEnv<BaselineMetrics>("EVAL_BASELINE_METRICS");
  const referenceMetrics = parseJsonEnv<ReferenceMetrics>("EVAL_REFERENCE_METRICS");

  const observedMetrics: ObservedMetrics | undefined =
    process.env.EVAL_OBSERVED_QUERY_LATENCY_MS
      ? {
          queryLatencyMs: parseNumber(process.env.EVAL_OBSERVED_QUERY_LATENCY_MS, 0),
          storageBytes: parseNumber(process.env.EVAL_OBSERVED_STORAGE_BYTES, 0),
          costPerQueryUsd: parseNumber(process.env.EVAL_OBSERVED_COST_PER_QUERY_USD, 0),
          tasksCompleted: parseNumber(process.env.EVAL_OBSERVED_TASKS_COMPLETED, 0),
          totalTasks: parseNumber(process.env.EVAL_OBSERVED_TOTAL_TASKS, 1),
        }
      : undefined;

  const handle = createAssertionContext(process.env);
  try {
    const { output, assertionLogs } = await runGateEvaluation({
      assertionsDir,
      context: handle.context,
      processExitCode,
      sessionLogPath: process.env.EVAL_SESSION_LOG_PATH,
      scenario: process.env.EVAL_SCENARIO ?? "unknown",
      version: process.env.EVAL_VERSION ?? "0.0.0",
      harness: process.env.EVAL_HARNESS ?? "base-rt",
      agent: process.env.EVAL_AGENT ?? "claude-code",
      model: process.env.MODEL ?? "unknown",
      runMetadata,
      efficiency: {
        wallClockSeconds,
        agentSteps,
        tokensUsed,
        llmApiCostUsd,
      },
      baselineMetrics,
      referenceMetrics,
      observedMetrics,
    });
    writeFileSync(assertionLogPath, `${JSON.stringify(assertionLogs, null, 2)}\n`, "utf8");
    process.stdout.write(`${JSON.stringify(output)}\n`);
  } finally {
    await handle.close();
  }
}

main().catch((error: unknown) => {
  const message = error instanceof Error ? error.message : String(error);
  process.stderr.write(`eval-core cli failed: ${message}\n`);
  process.exit(1);
});

import { createClient, type ClickHouseClient } from "@clickhouse/client";
import { Pool, type QueryResult } from "pg";

export interface PgClient {
  query: (text: string, params?: unknown[]) => Promise<QueryResult>;
}

const NOOP_PG: PgClient = {
  query: async () => {
    throw new Error("Postgres is not available in this scenario");
  },
};

export interface AssertionContext {
  pg: PgClient;
  clickhouse: ClickHouseClient;
  env: (key: string) => string | undefined;
}

export interface AssertionContextHandle {
  context: AssertionContext;
  close: () => Promise<void>;
}

export function createAssertionContext(
  env: NodeJS.ProcessEnv = process.env,
): AssertionContextHandle {
  const postgresUrl = env.POSTGRES_URL;
  const clickhouseUrl = env.CLICKHOUSE_URL;

  const pgPool = postgresUrl ? new Pool({ connectionString: postgresUrl }) : null;

  const clickhouse = clickhouseUrl
    ? createClient({ url: clickhouseUrl })
    : createClient({ url: "http://localhost:8123" });

  return {
    context: {
      pg: pgPool
        ? { query: (text: string, params?: unknown[]) => pgPool.query(text, params) }
        : NOOP_PG,
      clickhouse,
      env: (key: string) => env[key],
    },
    close: async () => {
      if (pgPool) await pgPool.end();
      await clickhouse.close();
    },
  };
}

import { readFileSync } from "node:fs";

import type { BaselineMetrics, ObservedMetrics, ReferenceMetrics } from "@dec-bench/scenarios";

import type { AssertionContext } from "./context.js";
import { loadScenarioAssertions, type AssertionFn } from "./discovery.js";
import type {
  AssertionLogMap,
  AssertionLogOutput,
  EvalOutput,
  GateName,
  GateResult,
} from "./types.js";
import { createEvalOutput } from "./output.js";
import { computeScore } from "./score.js";

const GATES: GateName[] = ["functional", "correct", "robust", "performant", "production"];
const PASS_THRESHOLD = 0.8;

export interface GateRunnerOptions {
  assertionsDir: string;
  context: AssertionContext;
  processExitCode: number;
  sessionLogPath?: string;
  scenario: string;
  version: string;
  harness: string;
  agent: string;
  model: string;
  runMetadata?: EvalOutput["run_metadata"];
  efficiency: EvalOutput["efficiency"];
  baselineMetrics?: BaselineMetrics;
  referenceMetrics?: ReferenceMetrics;
  observedMetrics?: ObservedMetrics;
}

export async function runGateEvaluation(
  options: GateRunnerOptions,
): Promise<{ output: EvalOutput; assertionLogs: AssertionLogOutput }> {
  const discovered = await loadScenarioAssertions(options.assertionsDir);
  const gates: Record<GateName, GateResult> = {
    functional: emptyGate(),
    correct: emptyGate(),
    robust: emptyGate(),
    performant: emptyGate(),
    production: emptyGate(),
  };
  const assertionLogs: AssertionLogOutput = {
    functional: { core: {}, scenario: {} },
    correct: { core: {}, scenario: {} },
    robust: { core: {}, scenario: {} },
    performant: { core: {}, scenario: {} },
    production: { core: {}, scenario: {} },
  };

  let blocked = false;
  let highestGate = 0;
  let scoreSum = 0;

  for (const gate of GATES) {
    if (blocked) {
      gates[gate] = emptyGate();
      continue;
    }

    const core = await runAssertions(
      getCoreAssertions(gate, options.processExitCode, options.sessionLogPath),
      options.context,
    );
    const scenario = await runAssertions(discovered[gate], options.context);
    const corePassed = allPassed(core.results);
    const scenarioScore = calcScore(scenario.results);
    const passed = corePassed && scenarioScore >= PASS_THRESHOLD;

    gates[gate] = {
      passed,
      score: scenarioScore,
      core: core.results,
      scenario: scenario.results,
    };
    assertionLogs[gate] = {
      core: core.logs,
      scenario: scenario.logs,
    };

    scoreSum += scenarioScore;
    if (passed) {
      highestGate += 1;
    } else {
      blocked = true;
    }
  }

  let compositeScore: EvalOutput["composite_score"];
  if (options.baselineMetrics && options.referenceMetrics && options.observedMetrics) {
    const breakdown = computeScore(
      options.baselineMetrics,
      options.referenceMetrics,
      options.observedMetrics,
    );
    compositeScore = {
      total: breakdown.total,
      components: breakdown.components,
    };
  }

  return {
    output: createEvalOutput({
      scenario: options.scenario,
      version: options.version,
      harness: options.harness,
      agent: options.agent,
      model: options.model,
      runMetadata: options.runMetadata,
      highestGate,
      normalizedScore: clamp(scoreSum / GATES.length),
      compositeScore,
      gates,
      efficiency: options.efficiency,
    }),
    assertionLogs,
  };
}

function emptyGate(): GateResult {
  return {
    passed: false,
    score: 0,
    core: {},
    scenario: {},
  };
}

function clamp(value: number): number {
  return Math.max(0, Math.min(1, value));
}

function calcScore(resultMap: Record<string, boolean>): number {
  const entries = Object.values(resultMap);
  if (entries.length === 0) {
    return 1;
  }

  const passedCount = entries.filter(Boolean).length;
  return clamp(passedCount / entries.length);
}

function allPassed(resultMap: Record<string, boolean>): boolean {
  return Object.values(resultMap).every(Boolean);
}

async function runAssertions(
  assertions: Record<string, AssertionFn>,
  context: AssertionContext,
): Promise<{ results: Record<string, boolean>; logs: AssertionLogMap }> {
  const results: Record<string, boolean> = {};
  const logs: AssertionLogMap = {};
  for (const [name, fn] of Object.entries(assertions)) {
    const started = Date.now();
    try {
      const outcome = await fn(context);
      const passed = Boolean(outcome.passed);
      results[name] = passed;
      logs[name] = {
        passed,
        durationMs: Date.now() - started,
        message: outcome.message,
        details: outcome.details,
      };
    } catch (error) {
      results[name] = false;
      logs[name] = {
        passed: false,
        durationMs: Date.now() - started,
        error: error instanceof Error ? error.stack ?? error.message : String(error),
      };
    }
  }
  return { results, logs };
}

function getCoreAssertions(
  gate: GateName,
  processExitCode: number,
  sessionLogPath?: string,
): Record<string, AssertionFn> {
  if (gate === "functional") {
    return {
      process_exits_clean: async () => ({
        passed: processExitCode === 0,
        message:
          processExitCode === 0
            ? "Agent process exited cleanly."
            : `Agent process exited with code ${processExitCode}.`,
        details: { exitCode: processExitCode },
      }),
      no_unhandled_errors: async () => {
        if (!sessionLogPath) {
          return {
            passed: true,
            message: "Session log path unavailable; unhandled error scan skipped.",
          };
        }
        const sessionLog = safeRead(sessionLogPath);
        if (!sessionLog) {
          return {
            passed: true,
            message: "Session log missing or unreadable; unhandled error scan skipped.",
            details: { sessionLogPath },
          };
        }
        const passed = !/unhandled|traceback|panic:/i.test(sessionLog);
        return {
          passed,
          message: passed
            ? "No unhandled errors, tracebacks, or panics found in session log."
            : "Unhandled error indicators found in session log.",
          details: { sessionLogPath },
        };
      },
    };
  }

  if (gate === "robust") {
    return {
      idempotent_rerun: async () => ({
        passed: true,
        message: "Idempotent rerun check is currently a placeholder assertion.",
      }),
    };
  }

  if (gate === "production") {
    return {
      uses_env_vars: async (ctx) => {
        const hasPostgres = Boolean(ctx.env("POSTGRES_URL"));
        const hasClickHouse = Boolean(ctx.env("CLICKHOUSE_URL"));
        const passed = hasPostgres && hasClickHouse;
        return {
          passed,
          message: passed
            ? "Required data store environment variables are available."
            : "Missing required data store environment variables.",
          details: {
            hasPostgresUrl: hasPostgres,
            hasClickhouseUrl: hasClickHouse,
          },
        };
      },
      no_secrets_in_code: async () => ({
        passed: true,
        message: "Secret scanning assertion is currently a placeholder.",
      }),
    };
  }

  return {};
}

function safeRead(path: string): string | null {
  try {
    return readFileSync(path, "utf8");
  } catch {
    return null;
  }
}

#!/usr/bin/env bash
set -euo pipefail

PROMPT_FILE="/scenario/prompts/${PERSONA:-naive}.md"
OUTPUT_DIR="${OUTPUT_DIR:-/output}"
METRICS_PATH="${OUTPUT_DIR}/agent-metrics.json"
RUN_META_PATH="${OUTPUT_DIR}/run-meta.json"
AGENT_RAW_PATH="${OUTPUT_DIR}/agent-raw.json"
TRACE_PATH="${OUTPUT_DIR}/agent-trace.json"
SESSION_JSONL_PATH="${OUTPUT_DIR}/session.jsonl"
export METRICS_PATH
export RUN_META_PATH
export AGENT_RAW_PATH
export TRACE_PATH
export SESSION_JSONL_PATH
export PROMPT_FILE

if [[ ! -f "${PROMPT_FILE}" ]]; then
  echo "Prompt file not found: ${PROMPT_FILE}" >&2
  exit 1
fi

if ! command -v agent >/dev/null 2>&1; then
  echo "Cursor Agent CLI is not installed in this image (missing 'agent' binary)." >&2
  exit 1
fi

if [[ -z "${CURSOR_API_KEY:-}" ]]; then
  echo "Missing API key: set CURSOR_API_KEY." >&2
  exit 1
fi

SYSTEM_PROMPT="You are running inside a sandboxed Docker container for a benchmark evaluation. You have full tool access. Do NOT ask for permission or propose commands for the user to run. Execute all fixes directly, then verify they work by running the relevant scripts and queries yourself. IMPORTANT: never run long-lived servers in the foreground. Start them in the background (for example with '&' and redirected logs), then continue with the rest of the task. If you start a local API server, immediately verify it with curl and proceed. Your work is scored by automated assertions after you finish."
PROMPT_CONTENT="$(cat "${PROMPT_FILE}")"
FULL_PROMPT="${SYSTEM_PROMPT}

${PROMPT_CONTENT}"

mkdir -p "${OUTPUT_DIR}"

CURSOR_MODEL="${MODEL:-auto}"
if [[ "${CURSOR_MODEL}" == "composer" ]]; then
  CURSOR_MODEL="composer-1.5"
fi

node -e '
const fs = require("node:fs");
const crypto = require("node:crypto");

const promptPath = process.env.PROMPT_FILE;
if (!promptPath) {
  process.stderr.write("PROMPT_FILE not provided.\n");
  process.exit(1);
}
const runMetaPath = process.env.RUN_META_PATH;
if (!runMetaPath) {
  process.stderr.write("RUN_META_PATH not provided.\n");
  process.exit(1);
}
const promptContent = fs.readFileSync(promptPath, "utf8");
const promptSha256 = crypto.createHash("sha256").update(promptContent, "utf8").digest("hex");
const persona = process.env.PERSONA || "naive";
const planMode = process.env.PLAN_MODE || "no-plan";
const metadata = {
  agent: "cursor",
  persona,
  planMode,
  promptPath,
  promptSha256,
  promptContent,
  promptPreview: promptContent.slice(0, 1000),
};
fs.writeFileSync(runMetaPath, `${JSON.stringify(metadata, null, 2)}\n`, "utf8");
'

set +e
CURSOR_OUTPUT="$(
  CURSOR_API_KEY="${CURSOR_API_KEY}" \
    agent \
      -p "${FULL_PROMPT}" \
      --output-format stream-json \
      --sandbox disabled \
      --force \
      --trust \
      --model "${CURSOR_MODEL}"
)"
cursor_exit_code=$?
set -e

printf '%s' "${CURSOR_OUTPUT}" | node -e '
const fs = require("node:fs");

const raw = fs.readFileSync(0, "utf8");
const rawPath = process.env.AGENT_RAW_PATH;
const sessionJsonlPath = process.env.SESSION_JSONL_PATH;
const tracePath = process.env.TRACE_PATH;
const metricsPath = process.env.METRICS_PATH;
if (!rawPath || !metricsPath) {
  process.stderr.write("AGENT_RAW_PATH or METRICS_PATH missing.\n");
  process.exit(1);
}

fs.writeFileSync(rawPath, raw.endsWith("\n") ? raw : `${raw}\n`, "utf8");
if (sessionJsonlPath) {
  fs.writeFileSync(sessionJsonlPath, raw.endsWith("\n") ? raw : `${raw}\n`, "utf8");
}

const lines = raw.split("\n").filter((line) => line.trim().length > 0);
const parsedEvents = [];
const passthroughLines = [];
for (const line of lines) {
  try {
    parsedEvents.push(JSON.parse(line));
  } catch {
    passthroughLines.push(line);
  }
}

const toNumber = (value) => {
  const n = Number(value);
  return Number.isFinite(n) ? n : 0;
};

let inputTokens = 0;
let outputTokens = 0;
let totalCostUsd = 0;
let agentSteps = 0;
const assistantMessages = [];
const traceEvents = [];

let idx = 0;
for (const evt of parsedEvents) {
  idx += 1;
  const type = typeof evt?.type === "string" ? evt.type : "unknown";
  traceEvents.push({
    id: `evt-${idx}`,
    kind: type,
    timestamp: evt?.timestamp ?? null,
    payload: evt,
  });

  if (/(turn|step)\.completed$/i.test(type) || type === "turn_completed" || type === "step_completed") {
    agentSteps += 1;
  }

  const usageCandidate = evt?.usage ?? evt?.tokenUsage ?? evt?.metrics ?? null;
  if (usageCandidate && typeof usageCandidate === "object") {
    inputTokens += toNumber(
      usageCandidate.input_tokens ??
        usageCandidate.inputTokens ??
        usageCandidate.prompt_tokens ??
        usageCandidate.promptTokens
    );
    outputTokens += toNumber(
      usageCandidate.output_tokens ??
        usageCandidate.outputTokens ??
        usageCandidate.completion_tokens ??
        usageCandidate.completionTokens
    );
    totalCostUsd += toNumber(
      usageCandidate.total_cost_usd ??
        usageCandidate.totalCostUsd ??
        usageCandidate.cost_usd ??
        usageCandidate.costUsd
    );
  }

  const directText = typeof evt?.text === "string" ? evt.text : "";
  const contentText = typeof evt?.content === "string" ? evt.content : "";
  const messageText = typeof evt?.message === "string" ? evt.message : "";
  const typeLooksAssistant = /assistant|final|response|message/i.test(type);
  if (typeLooksAssistant) {
    const candidate = directText || contentText || messageText;
    if (candidate) {
      assistantMessages.push(candidate);
    }
  }
}

if (agentSteps === 0) {
  agentSteps = parsedEvents.length;
}

const finalText =
  assistantMessages.length > 0
    ? assistantMessages[assistantMessages.length - 1]
    : passthroughLines.length > 0
      ? passthroughLines[passthroughLines.length - 1]
      : "";

if (finalText) {
  process.stdout.write(finalText);
  if (!finalText.endsWith("\n")) {
    process.stdout.write("\n");
  }
}

const metrics = {
  agentSteps,
  tokensUsed: inputTokens + outputTokens,
  llmApiCostUsd: totalCostUsd,
};
fs.writeFileSync(metricsPath, `${JSON.stringify(metrics, null, 2)}\n`, "utf8");

const trace = {
  schemaVersion: "2",
  source: "cursor-stream-json",
  summary: {
    eventCount: traceEvents.length,
    agentSteps,
    assistantMessageCount: assistantMessages.length,
  },
  usage: {
    inputTokens,
    outputTokens,
    totalCostUsd,
  },
  events: traceEvents,
};

if (tracePath) {
  fs.writeFileSync(tracePath, `${JSON.stringify(trace, null, 2)}\n`, "utf8");
}
'

exit "${cursor_exit_code}"

