  };
}

export async function no_null_event_ids(ctx: AssertionContext): Promise<AssertionResult> {
  const rows = await queryRows<{ n: number }>(
    ctx,
    "SELECT count() AS n FROM analytics.events WHERE event_id = '' OR event_id IS NULL",
  );
  const count = Number(rows[0]?.n ?? 0);
  const passed = count === 0;
  return {
    passed,
    message: passed ? "No null event IDs." : `Found ${count} null/empty event IDs.`,
    details: { count },
  };
}

export async function dates_are_valid(ctx: AssertionContext): Promise<AssertionResult> {
  const rows = await queryRows<{ n: number }>(
    ctx,
    "SELECT count() AS n FROM analytics.events WHERE event_ts < '2026-01-01' OR event_ts > '2026-12-31'",
  );
  const count = Number(rows[0]?.n ?? 0);
  const passed = count === 0;
  return {
    passed,
    message: passed ? "Dates are valid." : `Found ${count} out-of-range dates.`,
    details: { count },
  };
}

import type { AssertionContext, AssertionResult } from "@dec-bench/eval-core";

export async function scan_query_under_100ms(ctx: AssertionContext): Promise<AssertionResult> {
  const start = Date.now();
  await ctx.clickhouse.query({
    query: "SELECT event_type, count() AS n, sum(value) AS total FROM analytics.events GROUP BY event_type",
    format: "JSONEachRow",
  });
  const elapsed = Date.now() - start;
  const passed = elapsed < 100;
  return {
    passed,
    message: passed ? "Scan query under 100ms." : `Scan query took ${elapsed}ms.`,
    details: { elapsedMs: elapsed },
  };
}

import type { AssertionContext, AssertionResult } from "@dec-bench/eval-core";

async function queryRows<T>(ctx: AssertionContext, sql: string): Promise<T[]> {
  const result = await ctx.clickhouse.query({ query: sql, format: "JSONEachRow" });
  return (await (result as any).json()) as T[];
}

export async function no_duplicate_header_rows(ctx: AssertionContext): Promise<AssertionResult> {
  const rows = await queryRows<{ n: number }>(
    ctx,
    "SELECT count() AS n FROM analytics.events WHERE event_id = 'event_id'",
  );
  const count = Number(rows[0]?.n ?? 0);
  const passed = count === 0;
  return {
    passed,
    message: passed ? "No duplicate header rows." : `Found ${count} header rows.`,
    details: { count },
  };
}

export async function null_values_handled(ctx: AssertionContext): Promise<AssertionResult> {
  const rows = await queryRows<{ min_val: number }>(
    ctx,
    "SELECT min(value) AS min_val FROM analytics.events",
  );
  const minVal = Number(rows[0]?.min_val ?? -1);
  const passed = minVal >= 0;
  return {
    passed,
    message: passed ? "Null values handled." : `Min value ${minVal} indicates null handling issue.`,
    details: { minVal },
  };
}

import type { AssertionContext, AssertionResult } from "@dec-bench/eval-core";

export async function connection_env_vars_available(ctx: AssertionContext): Promise<AssertionResult> {
  const hasClickHouse = Boolean(ctx.env("CLICKHOUSE_URL"));
  const passed = hasClickHouse;
  return {
    passed,
    message: passed ? "Connection env vars available." : "Missing CLICKHOUSE_URL.",
    details: { hasClickHouse },
  };
}

export async function no_temporary_tables(ctx: AssertionContext): Promise<AssertionResult> {
  const result = await ctx.clickhouse.query({
    query: "SELECT count() AS n FROM system.tables WHERE database = 'analytics' AND name LIKE '%tmp%'",
    format: "JSONEachRow",
  });
  const rows = (await (result as any).json()) as Array<{ n: number }>;
  const count = Number(rows[0]?.n ?? 0);
  const passed = count === 0;
  return {
    passed,
    message: passed ? "No temporary tables." : `Found ${count} tmp tables.`,
    details: { count },
  };
}

